const { chromium } = require('playwright');
const path = require('path');

(async () => {
    let browser;
    try {
        console.log('рЯЪА Iniciando Playwright...');
        browser = await chromium.launch({ headless: true });

        const context = await browser.createContext({
            viewport: { width: 1080, height: 1920 },
            userAgent: 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36'
        });

        const page = await context.newPage();

        console.log('рЯУ± Abrindo perfil @marianacappelin...');
        await page.goto('https://instagram.com/marianacappelin', {
            waitUntil: 'networkidle',
            timeout: 30000
        });

        // Aguarda elementos carregarem
        await page.waitForTimeout(3000);

        const timestamp = new Date().toISOString().replace(/[:.]/g, '-');
        const filename = `instagram-marianacappelin-${timestamp}.png`;
        const filepath = path.join(process.cwd(), filename);

        console.log('рЯУЄ Capturando screenshot...');
        await page.screenshot({
            path: filepath,
            fullPage: true
        });

        console.log(`вЬЕ Screenshot salvo: ${filepath}`);
        console.log(`рЯУК Dimens√µes: ${page.viewportSize().width}x${page.viewportSize().height}`);

        await context.close();
        await browser.close();

    } catch (error) {
        console.error('вЭМ Erro:', error.message);
        if (browser) await browser.close();
        process.exit(1);
    }
})();

